const raw = $input.first().json.data;

const EXCLUDED_TITLE = [
  'senior', 'staff', 'lead', 'principal', 'director',
  'phd', 'ph.d', 'mba', 'manager', '🎓', 'head of'
];

const EXCLUDED_HARDWARE = [
  'hardware', 'firmware', 'embedded', 'fpga', 'asic',
  'pcb', 'mechanical', 'electrical', 'vlsi', 'vhdl', 'verilog',
  'design methodology', 'design verification', 'design emulation', 'design validation'
];

const extractUrl = (cell) => {
  const matches = [...cell.matchAll(/\(https?:\/\/[^)]+\)/g)];
  if (!matches.length) return null;
  const last = matches[matches.length - 1][0];
  return last.slice(1, -1);
};

const isClosed = (cell) =>
  cell.includes('🔒') || cell.toLowerCase().includes('closed');

const locationOk = (loc) => {
  const l = loc.toLowerCase();
  return l.includes('toronto') || l.includes('remote');
};

const titleOk = (role) => {
  const r = role.toLowerCase();
  return !EXCLUDED_TITLE.some(kw => r.includes(kw)) &&
         !EXCLUDED_HARDWARE.some(kw => r.includes(kw));
};

const jobs = [];
let headers = [];
let inTable = false;
let lastCompany = '';

for (const rawLine of raw.split('\n')) {
  const line = rawLine.trim();
  if (!line.startsWith('|')) { inTable = false; continue; }
  const cells = line.split('|').slice(1, -1).map(c => c.trim());
  if (!cells.length) continue;
  if (cells[0].toLowerCase().includes('company')) {
    headers = cells.map(c => c.toLowerCase().replace(/[^a-z]/g, ''));
    inTable = true;
    continue;
  }
  if (cells.every(c => /^[-: ]+$/.test(c))) continue;
  if (!inTable || cells.length < 4) continue;
  const row = {};
  headers.forEach((h, i) => { if (i < cells.length) row[h] = cells[i]; });
  let company = row['company'] ?? '';
  if (company === '↳' || company === '') {
    company = lastCompany;
  } else {
    lastCompany = company;
  }
  const role = row['role'] ?? '';
  const location = row['location'] ?? '';
  const applyCell = row['apply'] ?? '';
  if (isClosed(applyCell)) continue;
  const url = extractUrl(applyCell);
  if (!url) continue;
  if (url.includes('linkedin.com')) continue;
  if (!locationOk(location)) continue;
  if (!titleOk(role)) continue;
  jobs.push({ json: { url, title: `${role} — ${company}`, salary: null, description: null, location } });
}

return jobs;

const raw = $input.first().json.data;

const EXCLUDED_TITLE = ['senior','staff','lead','principal','director','phd','ph.d','mba','manager','head of'];
const SKIP_CATEGORIES = ['hardware / firmware', 'hardware/firmware'];

const extractUrl = (cell) => {
  const match = cell.match(/\(<?(https?:\/\/[^>)]+)>?\)/);
  return match ? match[1] : null;
};

const locationOk = (loc) => {
  const l = loc.toLowerCase();
  return l.includes('toronto') || l.includes('remote');
};

const titleOk = (title) => {
  const t = title.toLowerCase();
  return !EXCLUDED_TITLE.some(kw => t.includes(kw));
};

const cleanTitle = (title) => title.replace(/<!--[^>]+-->/g,'').replace(/[🔥💤🆕]/gu,'').replace(/^[\s\W]+/,'').trim();
const stripWorkType = (loc) => loc.replace(/\s*\([^)]+\)\s*$/,'').trim();

const jobs = [];
let headers = [], inTable = false, skipCategory = false;

for (const rawLine of raw.split('\n')) {
  const line = rawLine.trim();
  if (line.startsWith('## ')) {
    const cat = line.replace(/^##\s*/,'').toLowerCase();
    skipCategory = SKIP_CATEGORIES.some(c => cat.includes(c));
    inTable = false; continue;
  }
  if (skipCategory) continue;
  if (!line.startsWith('|')) { inTable = false; continue; }
  const cells = line.split('|').slice(1,-1).map(c => c.trim());
  if (!cells.length) continue;
  if (cells[0].toLowerCase().includes('title')) {
    headers = cells.map(c => c.toLowerCase().replace(/[^a-z]/g,''));
    inTable = true; continue;
  }
  if (cells.every(c => /^[-:|\s]+$/.test(c))) continue;
  if (!inTable || cells.length < 4) continue;
  const row = {};
  headers.forEach((h,i) => { if (i < cells.length) row[h] = cells[i]; });
  const rawTitle = row['title'] || '';
  const title = cleanTitle(rawTitle);
  const company = (row['company'] || '').trim();
  const rawLocation = row['location'] || '';
  const location = stripWorkType(rawLocation);
  const applyCell = row['apply'] || '';
  const url = extractUrl(applyCell);
  if (!url) continue;
  if (url.includes('linkedin.com')) continue;
  if (!locationOk(rawLocation)) continue;
  if (!titleOk(title)) continue;
  if (!title || !company) continue;
  jobs.push({ json: { url, title: `${title} — ${company}`, salary: null, description: null, location } });
}

return jobs;

const fs = require('fs');
const items = $input.all();
const jobs = items.map(i => i.json);
fs.writeFileSync('/tmp/n8n_jobs.json', JSON.stringify(jobs));
return [{ json: { count: jobs.length } }];

const fs = require('fs');
const https = require('https');

const shaFile = '/tmp/n8n_readme_shas.json';
const repos = [
  { key: 'canadian', url: 'https://api.github.com/repos/negarprh/Canadian-Tech-Internships-2026/commits?path=README.md&per_page=1' },
  { key: 'hanzili',  url: 'https://api.github.com/repos/hanzili/canada_sde_intern_position/commits?path=README.md&per_page=1' }
];

let stored = {};
try { stored = JSON.parse(fs.readFileSync(shaFile, 'utf8')); } catch {}

const fetchSHA = (url) => new Promise((resolve, reject) => {
  const options = { headers: { 'User-Agent': 'n8n-applypilot/1.0', 'Accept': 'application/vnd.github.v3+json' } };
  https.get(url, options, (res) => {
    let data = '';
    res.on('data', d => data += d);
    res.on('end', () => {
      try {
        const parsed = JSON.parse(data);
        resolve(Array.isArray(parsed) && parsed.length ? parsed[0].sha : null);
      } catch { reject(new Error('GitHub API parse error')); }
    });
  }).on('error', reject);
});

const results = await Promise.all(repos.map(r => fetchSHA(r.url)));
const current = {};
repos.forEach((r, i) => { current[r.key] = results[i]; });

const changed = repos.some(r => current[r.key] !== stored[r.key]);
if (!changed) {
  console.log('No README changes, skipping.');
  return [];
}

fs.writeFileSync(shaFile, JSON.stringify(current));
return [{ json: { shas: current } }];
